UPDATE books_clerk_writs SET content = json_set(content, '$.status', 'open') WHERE id = 'w-mo0xba3d-3883ba01cf33';
UPDATE books_spider_rigs SET content = json_set(
  json_set(
    json_set(content, '$.status', 'running'),
    '$.engines[8].status', 'pending'
  ),
  '$.engines[8].error', null
) WHERE id = 'rig-mo0xbdt0-3a7e7f9a';
" && echo "Patched: writ → open, seal → pending, rig → running" && sqlite3 "$GUILD_DB" "SELECT json_extract(e.value, '$.id') as engine, json_extract(e.value, '$.status') as status FROM books_spider_rigs r, json_each(json_extract(r.content, '$.engines')) e WHERE r.id = 'rig-mo0xbdt0-3a7e7f9a'"

GUILD_DB="/workspace/vibers/.nexus/nexus.db" && sqlite3 "$GUILD_DB" "
UPDATE books_spider_rigs SET content = json_set(
  json_set(
    json_remove(content, '$.engines[8]'),
    '$.engines[7].status', 'pending'
  ),
  '$.engines[7].error', null
) WHERE id = 'rig-mo0xbdt0-3a7e7f9a';
" && sqlite3 "$GUILD_DB" "SELECT json_extract(e.value, '$.id') as engine, json_extract(e.value, '$.status') as status FROM books_spider_rigs r, json_each(json_extract(r.content, '$.engines')) e WHERE r.id = 'rig-mo0xbdt0-3a7e7f9a'"

